() => {
  const clamp = (v, min, max) => Math.max(min, Math.min(max, v));

  const targetBtn = document.querySelector("button[data-qa-id='toolBarButtonToggle']:has(gs-icon[aria-label='troubleshoot'])");
  const mainMenu = document.querySelector('gs-menu#cdk-menu-11');
  const subMenu = document.querySelector('gs-menu#cdk-menu-13');
  if (!targetBtn || !mainMenu || !subMenu) return;

  // Reducir ruido de otros toggles cercanos.
  document.querySelectorAll("button[data-qa-id='toolBarButtonToggle']").forEach((btn) => {
    if (btn !== targetBtn) btn.style.visibility = 'hidden';
  });

  // Simular estado hover del boton objetivo.
  targetBtn.style.background = 'rgba(109, 255, 231, 0.16)';
  targetBtn.style.boxShadow = 'inset 0 0 0 1px rgba(109, 255, 231, 0.65)';
  targetBtn.style.borderRadius = '12px';
  const icon = targetBtn.querySelector("gs-icon[aria-label='troubleshoot']");
  if (icon) {
    icon.style.color = 'var(--color-primary)';
    icon.querySelectorAll('svg path').forEach((p) => p.style.setProperty('fill', 'var(--color-primary)', 'important'));
  }

  const menuWrap = mainMenu.closest('.cdk-overlay-connected-position-bounding-box');
  const subWrap = subMenu.closest('.cdk-overlay-connected-position-bounding-box');
  [menuWrap, subWrap].forEach((wrap) => {
    if (!wrap) return;
    wrap.style.left = '0px';
    wrap.style.top = '0px';
    wrap.style.width = '100vw';
    wrap.style.height = '100vh';
    wrap.style.position = 'fixed';
    wrap.style.display = 'block';
    wrap.style.transform = 'none';
  });

  const mainPane = mainMenu.closest('.cdk-overlay-pane');
  const subPane = subMenu.closest('.cdk-overlay-pane');
  if (!mainPane || !subPane) return;
  mainPane.style.position = 'fixed';
  mainPane.style.transform = 'none';
  subPane.style.position = 'fixed';
  subPane.style.transform = 'none';

  const gap = 10;
  const margin = 12;
  const br = targetBtn.getBoundingClientRect();
  const mr = mainMenu.getBoundingClientRect();
  const sr = subMenu.getBoundingClientRect();

  // Colocar menu principal debajo del boton y dejar espacio para submenu a la derecha.
  const maxMainLeft = window.innerWidth - margin - mr.width - gap - sr.width;
  const mainLeft = clamp(Math.round(br.left - 28), margin, Math.max(margin, maxMainLeft));
  const mainTop = clamp(Math.round(br.bottom + 8), margin, window.innerHeight - margin - mr.height);
  mainPane.style.left = `${mainLeft}px`;
  mainPane.style.top = `${mainTop}px`;
  mainPane.style.right = 'auto';
  mainPane.style.bottom = 'auto';

  const triggerItem = Array.from(mainMenu.querySelectorAll('button[role="menuitem"]')).find((b) => (b.textContent || '').includes('KPIs de conductor'));
  if (!triggerItem) return;

  // Evidenciar que se hace click en el item que despliega el ultimo menu.
  triggerItem.style.background = 'rgba(109, 255, 231, 0.14)';
  triggerItem.style.outline = '1px solid rgba(109, 255, 231, 0.65)';
  triggerItem.style.borderRadius = '8px';

  // Posicionar submenu a la derecha del item (sin recortarse).
  const tr = triggerItem.getBoundingClientRect();
  const subLeft = clamp(Math.round(tr.right + gap), margin, window.innerWidth - margin - sr.width);
  const subTop = clamp(Math.round(tr.top + (tr.height / 2) - (sr.height / 2)), margin, window.innerHeight - margin - sr.height);
  subPane.style.left = `${subLeft}px`;
  subPane.style.top = `${subTop}px`;
  subPane.style.right = 'auto';
  subPane.style.bottom = 'auto';
}
